from math import isfinite

class Signal:
    def __init__(self, score=0.0):
        self._score = 0.0
        self.score = score

    @property
    def score(self):
        return self._score

    @score.setter
    def score(self, v):
        if not isinstance(v, (int, float)) or not isfinite(v) or not (0 <= float(v) <= 1):
            raise ValueError('score fuera de rango')
        self._score = float(v)

s = Signal(0.4)
print(s.score)
for bad in [1.5, float('nan')]:
    try:
        s.score = bad
    except ValueError as e:
        print(e)

