class MutableEntity:
    def __init__(self, eid):
        self.eid = eid
    def __hash__(self):
        return hash(self.eid)
    def __eq__(self, o):
        return isinstance(o, MutableEntity) and self.eid == o.eid

m = MutableEntity('E1')
d = {m: 'ok'}
m.eid = 'E2'  # rompe lookup
print('BUG', d.get(m))
# SAFE: key inmutable
safe = {'E1': 'ok'}
print('SAFE', safe.get('E1'))

